mapper.select:
SELECT session_id, user_id, dept_id, title, message_count, last_message_time, create_time
FROM kb_qa_session
WHERE session_id = #{sessionId}

mapper.update:
UPDATE kb_qa_session
SET title = #{title},
    message_count = #{messageCount},
    last_message_time = #{lastMessageTime}
WHERE session_id = #{sessionId}

mapper.delete:
DELETE FROM kb_qa_session
WHERE session_id = #{sessionId}
  AND user_id = #{userId}
